<script>
const labels=["File","Edit","View"];let active=$state(labels[0]);function activate(x){active=x}function navigate(e,x){let i=labels.indexOf(x);if(e.key==='ArrowRight')i=(i+1)%labels.length;else if(e.key==='ArrowLeft')i=(i-1+labels.length)%labels.length;else if(e.key==='Home')i=0;else if(e.key==='End')i=labels.length-1;else if(false&&(e.key==='Enter'||e.key===' ')){activate(x);return}else return;e.preventDefault();const group=e.currentTarget.parentElement;active=labels[i];queueMicrotask(()=>group?.querySelectorAll('[role=menuitem]')[i]?.focus())}
</script>
<main class="nav-shell"><h1>MenuBar</h1><div class="menubar" role="menubar" aria-label="Application"><button role="menuitem" tabindex={active==="File"?0:-1} onclick={()=>activate("File")} onkeydown={(event)=>navigate(event,"File")}>File</button><button role="menuitem" tabindex={active==="Edit"?0:-1} onclick={()=>activate("Edit")} onkeydown={(event)=>navigate(event,"Edit")}>Edit</button><button role="menuitem" tabindex={active==="View"?0:-1} onclick={()=>activate("View")} onkeydown={(event)=>navigate(event,"View")}>View</button></div></main>
